import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import GlassCard from '../components/common/GlassCard';

const Register = () => {
    const [role, setRole] = useState('parent');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [fullName, setFullName] = useState('');
    const [city, setCity] = useState('');
    const [error, setError] = useState('');
    const { register } = useAuth();
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (email.includes('@admin.com')) {
            setError('No puedes registrarte con este correo');
            return;
        }
        try {
            const user = await register({ email, password, role, full_name: fullName, city });
            if (user.role === 'parent') navigate('/dashboard/parent');
            else navigate('/dashboard/sitter');
        } catch (err) {
            setError(err.response?.data?.message || 'Error al registrarse');
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center p-4">
            <GlassCard className="w-full max-w-md mt-16">
                <h2 className="text-3xl font-bold text-center mb-6 text-dark">Registrarse</h2>
                {error && <div className="bg-red-100 text-red-600 p-3 rounded-lg mb-4 text-center">{error}</div>}

                <div className="flex gap-4 mb-6">
                    <button 
                        onClick={() => setRole('parent')}
                        className={`flex-1 py-3 rounded-xl border-2 transition ${role === 'parent' ? 'border-primary bg-primary/10 text-primary font-bold' : 'border-gray-200 text-gray-500'}`}
                    >
                        Soy Padre
                    </button>
                    <button 
                        onClick={() => setRole('sitter')}
                        className={`flex-1 py-3 rounded-xl border-2 transition ${role === 'sitter' ? 'border-primary bg-primary/10 text-primary font-bold' : 'border-gray-200 text-gray-500'}`}
                    >
                        Soy Cuidador
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="flex flex-col gap-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Nombre Completo</label>
                        <input type="text" className="w-full p-3 rounded-xl border border-gray-300 focus:ring-2 focus:ring-primary outline-none" value={fullName} onChange={e => setFullName(e.target.value)} required />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Email</label>
                        <input type="email" className="w-full p-3 rounded-xl border border-gray-300 focus:ring-2 focus:ring-primary outline-none" value={email} onChange={e => setEmail(e.target.value)} required />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Ciudad</label>
                        <input type="text" className="w-full p-3 rounded-xl border border-gray-300 focus:ring-2 focus:ring-primary outline-none" value={city} onChange={e => setCity(e.target.value)} required />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Contraseña</label>
                        <input type="password" className="w-full p-3 rounded-xl border border-gray-300 focus:ring-2 focus:ring-primary outline-none" value={password} onChange={e => setPassword(e.target.value)} required minLength={6}/>
                    </div>
                    <button type="submit" className="w-full bg-primary text-white py-3 rounded-xl font-semibold hover:bg-primary/90 transition shadow-lg mt-4">
                        Crear Cuenta
                    </button>
                </form>
            </GlassCard>
        </div>
    );
};

export default Register;
